A more sophisticated approach is to draw a corresponding box drawing intersection (like in `laststatus=3`) instead of always a vertical separator. The diff that achieves 90% of this behavior (it doesn't work for when there is split to the left but not a statusline to the left):

<details><summary>Diff for box drawing intersection separators</summary>

```diff
diff --git a/src/nvim/drawscreen.c b/src/nvim/drawscreen.c
index a7fa6bf688..22e9eeb0d2 100644
--- a/src/nvim/drawscreen.c
+++ b/src/nvim/drawscreen.c
@@ -121,14 +121,6 @@
 #include "nvim/vim_defs.h"
 #include "nvim/window.h"

-/// corner value flags for hsep_connected and vsep_connected
-typedef enum {
-  WC_TOP_LEFT = 0,
-  WC_TOP_RIGHT,
-  WC_BOTTOM_LEFT,
-  WC_BOTTOM_RIGHT,
-} WindowCorner;
-
 #include "drawscreen.c.generated.h"

 static bool redraw_popupmenu = false;
@@ -1268,7 +1260,7 @@ static void draw_hsep_win(win_T *wp)
 }

 /// Get the separator connector for specified window corner of window "wp"
-static schar_T get_corner_sep_connector(win_T *wp, WindowCorner corner)
+schar_T get_corner_sep_connector(win_T *wp, WindowCorner corner)
 {
   // It's impossible for windows to be connected neither vertically nor horizontally
   // So if they're not vertically connected, assume they're horizontally connected
diff --git a/src/nvim/drawscreen.h b/src/nvim/drawscreen.h
index a7b38276b2..c9f3a7e65e 100644
--- a/src/nvim/drawscreen.h
+++ b/src/nvim/drawscreen.h
@@ -18,6 +18,14 @@ enum {
   UPD_CLEAR        = 50,  ///< screen messed up, clear it
 };

+/// corner value flags for hsep_connected and vsep_connected
+typedef enum {
+  WC_TOP_LEFT = 0,
+  WC_TOP_RIGHT,
+  WC_BOTTOM_LEFT,
+  WC_BOTTOM_RIGHT,
+} WindowCorner;
+
 /// While redrawing the screen this flag is set.  It means the screen size
 /// ('lines' and 'rows') must not be changed.
 EXTERN bool updating_screen INIT( = false);
diff --git a/src/nvim/statusline.c b/src/nvim/statusline.c
index f458efd8a7..91abbc57c8 100644
--- a/src/nvim/statusline.c
+++ b/src/nvim/statusline.c
@@ -93,12 +93,7 @@ void win_redr_status(win_T *wp)
   hlf_T group = HLF_C;
   // May need to draw the character below the vertical separator.
   if (wp->w_vsep_width != 0 && wp->w_status_height != 0 && redrawing()) {
-    schar_T fillchar;
-    if (stl_connected(wp)) {
-      fillchar = fillchar_status(&group, wp);
-    } else {
-      fillchar = wp->w_p_fcs_chars.vert;
-    }
+    schar_T fillchar = get_corner_sep_connector(wp, WC_BOTTOM_RIGHT);
     int attr = win_hl_attr(wp, (int)group);
     grid_line_start(&default_gridview, W_ENDROW(wp));
     grid_line_put_schar(W_ENDCOL(wp), fillchar, attr);
```

</details>

Here how the above example looks with default color scheme:

<img width="2880" height="1734" alt="Image" src="https://github.com/user-attachments/assets/23c7cabf-7c5c-4079-8d5a-d231ef4fe4e9" />

And here is a comparison of three approaches on a more complex window layout:

